// WS-Security Timestamp Validation Handler
class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final long TIMESTAMP_TOLERANCE_MS = 300_000; // 5 minutes
    private static final ConcurrentHashMap<String, Long> processedTimestamps = new ConcurrentHashMap<>();
    private static final SimpleDateFormat ISO_FORMAT = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
    private static final SimpleDateFormat ISO_FORMAT_ALT = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'");

    static {
        ISO_FORMAT.setTimeZone(TimeZone.getTimeZone("UTC"));
        ISO_FORMAT_ALT.setTimeZone(TimeZone.getTimeZone("UTC"));

        // Cleanup thread for expired timestamps
        Timer cleanupTimer = new Timer(true);
        cleanupTimer.scheduleAtFixedRate(new TimerTask() {
            @Override
            public void run() {
                long now = System.currentTimeMillis();
                processedTimestamps.entrySet().removeIf(entry ->
                        (now - entry.getValue()) > TIMESTAMP_TOLERANCE_MS * 2);
            }
        }, 60000, 60000);
    }

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSS_NS, "Security"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (outbound) {
            return addTimestampToOutbound(context);
        } else {
            return validateInboundTimestamp(context);
        }
    }

    private boolean addTimestampToOutbound(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                header = envelope.addHeader();
            }

            SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
            securityElement.addAttribute(envelope.createName("mustUnderstand", "soap",
                    "http://schemas.xmlsoap.org/soap/envelope/"), "1");

            SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);
            String timestampId = "TS-" + UUID.randomUUID().toString();
            timestampElement.addAttribute(envelope.createName("Id", "wsu", WSU_NS), timestampId);

            Date now = new Date();
            Date expires = new Date(now.getTime() + TIMESTAMP_TOLERANCE_MS);

            SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
            createdElement.addTextNode(ISO_FORMAT.format(now));

            SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
            expiresElement.addTextNode(ISO_FORMAT.format(expires));

            message.saveChanges();
            System.out.println("[WS-Security] Added timestamp to outbound message: " + ISO_FORMAT.format(now));
            return true;
        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error adding timestamp: " + e.getMessage());
            throw new RuntimeException("Failed to add WS-Security timestamp", e);
        }
    }

    private boolean validateInboundTimestamp(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPHeader header = message.getSOAPHeader();

            if (header == null) {
                System.err.println("[WS-Security] No SOAP header found - rejecting message");
                generateSecurityFault(context, "Missing WS-Security header");
                return false;
            }

            // Extract Security header
            Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));
            if (!securityHeaders.hasNext()) {
                System.err.println("[WS-Security] No Security element found - rejecting message");
                generateSecurityFault(context, "Missing WS-Security Security element");
                return false;
            }

            SOAPElement securityElement = (SOAPElement) securityHeaders.next();

            // Extract Timestamp
            Iterator<?> timestamps = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));
            if (!timestamps.hasNext()) {
                System.err.println("[WS-Security] No Timestamp element found - rejecting message");
                generateSecurityFault(context, "Missing WS-Security Timestamp");
                return false;
            }

            SOAPElement timestampElement = (SOAPElement) timestamps.next();

            // Extract Created and Expires values
            String createdValue = extractChildText(timestampElement, WSU_NS, "Created");
            String expiresValue = extractChildText(timestampElement, WSU_NS, "Expires");

            if (createdValue == null || createdValue.isEmpty()) {
                System.err.println("[WS-Security] Created timestamp is missing");
                generateSecurityFault(context, "Missing Created timestamp");
                return false;
            }

            Date createdDate = parseTimestamp(createdValue);
            if (createdDate == null) {
                System.err.println("[WS-Security] Cannot parse Created timestamp: " + createdValue);
                generateSecurityFault(context, "Invalid Created timestamp format");
                return false;
            }

            Date now = new Date();

            // Check if Created is not in the future (with tolerance)
            if (createdDate.getTime() > now.getTime() + TIMESTAMP_TOLERANCE_MS) {
                System.err.println("[WS-Security] Created timestamp is in the future: " + createdValue);
                generateSecurityFault(context, "Created timestamp is in the future");
                return false;
            }

            // Check if Created is not too old
            if (now.getTime() - createdDate.getTime() > TIMESTAMP_TOLERANCE_MS) {
                System.err.println("[WS-Security] Created timestamp is too old: " + createdValue);
                generateSecurityFault(context, "Message timestamp has expired (Created too old)");
                return false;
            }

            // Check Expires if present
            if (expiresValue != null && !expiresValue.isEmpty()) {
                Date expiresDate = parseTimestamp(expiresValue);
                if (expiresDate != null && now.after(expiresDate)) {
                    System.err.println("[WS-Security] Message has expired: " + expiresValue);
                    generateSecurityFault(context, "Message has expired");
                    return false;
                }
            }

            // Replay protection: check if this timestamp+id was already processed
            String timestampId = timestampElement.getAttribute("wsu:Id");
            if (timestampId == null || timestampId.isEmpty()) {
                timestampId = createdValue; // Use created value as key if no Id
            }

            String replayKey = timestampId + "|" + createdValue;
            if (processedTimestamps.putIfAbsent(replayKey, System.currentTimeMillis()) != null) {
                System.err.println("[WS-Security] Replay attack detected! Duplicate timestamp: " + replayKey);
                generateSecurityFault(context, "Replay attack detected - duplicate message");
                return false;
            }

            System.out.println("[WS-Security] Timestamp validated successfully. Created: " + createdValue
                    + ", Expires: " + expiresValue);
            return true;

        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error validating timestamp: " + e.getMessage());
            throw new RuntimeException("Failed to validate WS-Security timestamp", e);
        }
    }

    private String extractChildText(SOAPElement parent, String namespace, String localName) {
        Iterator<?> children = parent.getChildElements(new QName(namespace, localName));
        if (children.hasNext()) {
            SOAPElement child = (SOAPElement) children.next();
            return child.getTextContent();
        }
        return null;
    }

    private Date parseTimestamp(String timestamp) {
        try {
            return ISO_FORMAT.parse(timestamp);
        } catch (ParseException e1) {
            try {
                return ISO_FORMAT_ALT.parse(timestamp);
            } catch (ParseException e2) {
                return null;
            }
        }
    }

    private void generateSecurityFault(SOAPMessageContext context, String reason) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPBody body = message.getSOAPBody();
            body.removeContents();
            SOAPFault fault = body.addFault();
            fault.setFaultCode(new QName("http://schemas.xmlsoap.org/soap/envelope/", "Client"));
            fault.setFaultString("WS-Security validation failed: " + reason);
            message.saveChanges();
        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error generating fault: " + e.getMessage());
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        logMessage("FAULT", context);
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    private void logMessage(String type, SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            TransformerFactory tf = TransformerFactory.newInstance();
            Transformer transformer = tf.newTransformer();
            transformer.setOutputProperty(OutputKeys.INDENT, "yes");
            StringWriter sw = new StringWriter();
            transformer.transform(new DOMSource(message.getSOAPPart()), new StreamResult(sw));
            System.out.println("[WS-Security " + type + "] Message:\n" + sw.toString());
        } catch (Exception e) {
            System.err.println("[WS-Security] Error logging message: " + e.getMessage());
        }
    }
}

